/*
 * Get the segregated list index for a given block size.
 * Size classes: 16-32, 33-64, 65-128, 129-256, 257-512, 513-1024,
 *               1025-2048, 2049-4096, 4097-8192, 8193-16384, 16385-32768, 32769+
 */
static int
get_list_index(size_t size)
{
	if (size < 33) return 0;
	if (size < 65) return 1;
	if (size < 129) return 2;
	if (size < 257) return 3;
	if (size < 513) return 4;
	if (size < 1025) return 5;
	if (size < 2049) return 6;
	if (size < 4097) return 7;
	if (size < 8193) return 8;
	if (size < 16385) return 9;
	if (size < 32769) return 10;
	return 11;
}

/*
 * Insert a free block into the appropriate segregated list.
 * Always insert at the head of the list for O(1) operation.
 */
static void
insert_free_block(void *bp)
{
	size_t size = GET_SIZE(HDRP(bp));
	int index = get_list_index(size);

	SET_NEXT(bp, seg_lists[index]);
	SET_PREV(bp, NULL);
	if (seg_lists[index] != NULL)
		SET_PREV(seg_lists[index], bp);
	seg_lists[index] = bp;
}

/*
 * Remove a free block from its segregated list.
 */
static void
remove_free_block(void *bp)
{
	size_t size = GET_SIZE(HDRP(bp));
	int index = get_list_index(size);
	void *next = GET_NEXT(bp);
	void *prev = GET_PREV(bp);

	if (prev != NULL)
		SET_NEXT(prev, next);
	else
		seg_lists[index] = next;

	if (next != NULL)
		SET_PREV(next, prev);
}

